#!/usr/bin/env python
"""
SARS-CoV-2 PDB Structure Coverage Analysis

This script queries the RCSB PDB REST API for all structures deposited with
'SARS-CoV-2' organism annotation, extracts metadata, maps chains to SARS-CoV-2
proteome genes, and produces a coverage table and bar chart.
"""

import time
import requests
import pandas as pd
import matplotlib.pyplot as plt
from collections import defaultdict

# Rate limiting: RCSB PDB API guidelines suggest no more than 5 requests/second
RATE_LIMIT_DELAY = 0.25  # seconds between requests


def query_sars_cov2_structures():
    """
    Query RCSB PDB REST API for all structures with SARS-CoV-2 organism annotation.
    Uses the RCSB Search API v2.
    """
    search_url = "https://search.rcsb.org/rcsbsearch/v2/query"

    # Search query for SARS-CoV-2 structures
    query = {
        "query": {
            "type": "group",
            "logical_operator": "and",
            "nodes": [
                {
                    "type": "terminal",
                    "service": "text",
                    "parameters": {
                        "attribute": "rcsb_entity_source_organism.taxonomy_lineage.name",
                        "operator": "exact_match",
                        "value": "Severe acute respiratory syndrome coronavirus 2"
                    }
                }
            ]
        },
        "request_options": {
            "paginate": {
                "start": 0,
                "rows": 5000  # Get up to 5000 structures
            },
            "results_content_type": ["experimental"]
        },
        "return_type": "entry"
    }

    print("Querying RCSB PDB for SARS-CoV-2 structures...")
    response = requests.post(search_url, json=query, timeout=60)
    response.raise_for_status()

    results = response.json()
    total_count = results.get("total_count", 0)
    print(f"Found {total_count} SARS-CoV-2 structures")

    pdb_ids = [hit["identifier"] for hit in results.get("result_set", [])]

    # If there are more results, paginate
    while len(pdb_ids) < total_count and len(pdb_ids) < 10000:
        time.sleep(RATE_LIMIT_DELAY)
        query["request_options"]["paginate"]["start"] = len(pdb_ids)
        response = requests.post(search_url, json=query, timeout=60)
        response.raise_for_status()
        results = response.json()
        new_ids = [hit["identifier"] for hit in results.get("result_set", [])]
        if not new_ids:
            break
        pdb_ids.extend(new_ids)

    print(f"Retrieved {len(pdb_ids)} PDB IDs")
    return pdb_ids


def get_structure_metadata_batch(pdb_ids):
    """
    Fetch structure metadata using RCSB PDB GraphQL API in batches.
    Extracts: PDB ID, resolution, structure method, chain IDs, and UniProt accessions.
    """
    graphql_url = "https://data.rcsb.org/graphql"

    all_metadata = []
    batch_size = 50  # Process in batches to avoid overwhelming the API

    for i in range(0, len(pdb_ids), batch_size):
        batch = pdb_ids[i:i + batch_size]
        print(f"Fetching metadata for structures {i+1}-{min(i+batch_size, len(pdb_ids))}...")

        # GraphQL query for batch of structures
        ids_str = ', '.join([f'"{pid}"' for pid in batch])

        query = f"""
        {{
          entries(entry_ids: [{ids_str}]) {{
            rcsb_id
            exptl {{
              method
            }}
            rcsb_entry_info {{
              resolution_combined
            }}
            polymer_entities {{
              rcsb_polymer_entity_container_identifiers {{
                auth_asym_ids
              }}
              rcsb_entity_source_organism {{
                ncbi_taxonomy_id
                ncbi_scientific_name
              }}
              uniprots {{
                rcsb_uniprot_container_identifiers {{
                  uniprot_id
                }}
              }}
              rcsb_polymer_entity {{
                pdbx_description
              }}
            }}
          }}
        }}
        """

        try:
            response = requests.post(
                graphql_url,
                json={"query": query},
                timeout=60
            )
            response.raise_for_status()
            data = response.json()

            if "data" in data and "entries" in data["data"]:
                for entry in data["data"]["entries"]:
                    if entry is None:
                        continue
                    metadata = parse_entry_metadata(entry)
                    all_metadata.extend(metadata)
        except requests.exceptions.RequestException as e:
            print(f"Error fetching batch starting at {i}: {e}")
            # Try individual entries for failed batch
            for pid in batch:
                time.sleep(RATE_LIMIT_DELAY)
                meta = get_single_structure_metadata(pid)
                if meta:
                    all_metadata.extend(meta)

        time.sleep(RATE_LIMIT_DELAY)

    return all_metadata


def get_single_structure_metadata(pdb_id):
    """Fetch metadata for a single structure as fallback."""
    graphql_url = "https://data.rcsb.org/graphql"

    query = f"""
    {{
      entry(entry_id: "{pdb_id}") {{
        rcsb_id
        exptl {{
          method
        }}
        rcsb_entry_info {{
          resolution_combined
        }}
        polymer_entities {{
          rcsb_polymer_entity_container_identifiers {{
            auth_asym_ids
          }}
          rcsb_entity_source_organism {{
            ncbi_taxonomy_id
            ncbi_scientific_name
          }}
          uniprots {{
            rcsb_uniprot_container_identifiers {{
              uniprot_id
            }}
          }}
          rcsb_polymer_entity {{
            pdbx_description
          }}
        }}
      }}
    }}
    """

    try:
        response = requests.post(graphql_url, json={"query": query}, timeout=30)
        response.raise_for_status()
        data = response.json()

        if "data" in data and "entry" in data["data"] and data["data"]["entry"]:
            return parse_entry_metadata(data["data"]["entry"])
    except requests.exceptions.RequestException as e:
        print(f"Error fetching {pdb_id}: {e}")

    return []


